import logging
import os

class FilePathContext:
    def __init__(self, path):
        self.filepath = path if isinstance(path, str) else path.filepath
    def open(self, mode, encoding=None):
        if encoding:
            return open(self.filepath, mode, encoding=encoding)
        return open(self.filepath, mode)

def resolve_format(fmt, filepath):
    _, ext = os.path.splitext(filepath.lower())
    if ext in ['.tsv', '.txt']:
        return 'tsv'
    if ext in ['.yaml', '.yml']:
        return 'yaml'
    return None

def parse_exchange_table_file(f):
    header = f.readline()
    for line in f:
        stripped = line.strip()
        if not stripped or stripped.startswith('#'):
            continue
        parts = stripped.split('\t')
        if len(parts) != 3:
            continue
        compound = parts[0]
        try:
            lower = float(parts[1])
            upper = float(parts[2])
        except ValueError:
            continue
        if not compound.isalnum():
            continue
        if lower > upper:
            continue
        yield {'compound': compound, 'lower': lower, 'upper': upper}

def parse_exchange_yaml_file(context, f, default_compartment):
    for line in f:
        stripped = line.strip()
        if not stripped or stripped.startswith('#'):
            continue
        parts = stripped.split(':')
        if len(parts) < 3:
            continue
        compound = parts[0]
        try:
            lower = float(parts[1])
            upper = float(parts[2])
        except ValueError:
            continue
        if not compound.isalnum():
            continue
        if lower > upper:
            continue
        compartment = parts[3] if len(parts) > 3 else default_compartment
        yield {'compound': compound, 'lower': lower, 'upper': upper, 'compartment': compartment}

class ParseError(Exception):
    pass

logger = logging.getLogger(__name__)

def parse_exchange_file(path, default_compartment):
    context = FilePathContext(path)
    fmt = resolve_format(None, context.filepath)
    if fmt is None:
        # Content-based detection
        with context.open('r', encoding='utf-8-sig') as f:
            first_data_line = None
            while True:
                line = f.readline()
                if not line:
                    break
                stripped = line.strip()
                if stripped and not stripped.startswith('#'):
                    first_data_line = stripped
                    break
            if first_data_line is None:
                # Empty or only comments/whitespace
                return
            if first_data_line.startswith('compound'):
                fmt = 'tsv'
            else:
                fmt = 'yaml'
    if fmt == 'tsv':
        with context.open('r', encoding='utf-8-sig') as f:
            for entry in parse_exchange_table_file(f):
                yield entry
    elif fmt == 'yaml':
        with context.open('r', encoding='utf-8-sig') as f:
            for entry in parse_exchange_yaml_file(context, f, default_compartment):
                yield entry
    else:
        raise ParseError('Unable to detect format of exchange file {}'.format(context.filepath))

def main():
    # Create a sample TSV exchange file
    tsv_path = 'exchange_limits.tsv'
    with open(tsv_path, 'w') as f:
        f.write('compound\tlower\tupper\n')
        f.write('Glucose\t-10\t100\n')
        f.write('Lactate\t0\t50\n')

    print('Parsing TSV file:')
    for entry in parse_exchange_file(tsv_path, default_compartment='c'):
        print(entry)

    # Create a sample YAML-like exchange file
    yaml_path = 'exchange_limits.yaml'
    with open(yaml_path, 'w') as f:
        f.write('Glucose:-10:100:cytosol\n')
        f.write('O2:-1000:1000:mitochondria\n')

    print('\nParsing YAML file:')
    for entry in parse_exchange_file(yaml_path, default_compartment='c'):
        print(entry)

if __name__ == '__main__':
    main()
